import{_ as a,o as t,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"AI 模型","description":"","frontmatter":{},"headers":[],"relativePath":"features/models.md","filePath":"features/models.md"}'),o={name:"features/models.md"};function r(n,e,s,d,h,p){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="ai-模型" tabindex="-1">AI 模型 <a class="header-anchor" href="#ai-模型" aria-label="Permalink to &quot;AI 模型&quot;">​</a></h1><p>Lyra Code 支持多种 AI 模型服务商，让你能为不同任务灵活选择最佳模型。</p><h2 id="支持的服务商" tabindex="-1">支持的服务商 <a class="header-anchor" href="#支持的服务商" aria-label="Permalink to &quot;支持的服务商&quot;">​</a></h2><h3 id="openai-chat-completions" tabindex="-1">OpenAI Chat Completions <a class="header-anchor" href="#openai-chat-completions" aria-label="Permalink to &quot;OpenAI Chat Completions&quot;">​</a></h3><p>连接任意兼容 OpenAI Chat Completions 的 API，包括：</p><ul><li><strong>OpenAI</strong> — GPT-4o、GPT-4、o1、o3 系列</li><li><strong>第三方服务商</strong> — OpenRouter、Groq、Together AI 等兼容 API</li><li><strong>自部署方案</strong> — Ollama、vLLM、LocalAI 等</li></ul><h3 id="anthropic-messages-api" tabindex="-1">Anthropic Messages API <a class="header-anchor" href="#anthropic-messages-api" aria-label="Permalink to &quot;Anthropic Messages API&quot;">​</a></h3><p>完整支持 Anthropic Messages API：</p><ul><li>Claude Opus、Sonnet、Haiku 系列</li><li>流式与非流式模式</li><li>扩展思考（Extended Thinking）/ 推理深度控制</li></ul><h3 id="gemini-generatecontent-api" tabindex="-1">Gemini GenerateContent API <a class="header-anchor" href="#gemini-generatecontent-api" aria-label="Permalink to &quot;Gemini GenerateContent API&quot;">​</a></h3><p>原生支持 Google Gemini 模型：</p><ul><li>Gemini 2.5 Pro、2.5 Flash</li><li>Gemini 2.0 Flash、1.5 Pro</li><li>多模态输入（文本 + 图片）</li></ul><h2 id="服务商配置" tabindex="-1">服务商配置 <a class="header-anchor" href="#服务商配置" aria-label="Permalink to &quot;服务商配置&quot;">​</a></h2><p>每个服务商可配置以下参数：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>API 密钥</td><td>你的认证密钥</td></tr><tr><td>接口地址</td><td>API 端点（可自定义）</td></tr><tr><td>模型</td><td>模型名称 / 标识符</td></tr><tr><td>额外请求头</td><td>自定义 HTTP Headers</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">HTTP API 警告</p><p>使用 HTTP（非 HTTPS）API 地址会触发<strong>明确的安全警告</strong>。生产环境请务必使用 HTTPS。</p></div><h2 id="快速模型切换" tabindex="-1">快速模型切换 <a class="header-anchor" href="#快速模型切换" aria-label="Permalink to &quot;快速模型切换&quot;">​</a></h2><p>Lyra Code 支持在<strong>对话中途</strong>切换模型，无需丢失上下文：</p><ul><li>在不同服务商和模型之间即时切换</li><li>随时调整系统提示词</li><li>对支持的模型调整推理深度</li></ul><h2 id="模型配置方案" tabindex="-1">模型配置方案 <a class="header-anchor" href="#模型配置方案" aria-label="Permalink to &quot;模型配置方案&quot;">​</a></h2><p>将多个服务商配置保存为方案，每个方案可独立设置：</p><ul><li>API 密钥和端点</li><li>默认模型</li><li>首选系统提示词</li><li>推理参数</li></ul><p>根据任务类型——编程、创作、研究或自动化——快速切换方案。</p>',23)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
